class MinStack:

    def __init__(self):
        self.stack = []
        self.min_stack = []

    def push(self, val: int) -> None:
        self.stack.append(val)
        if not self.min_stack or val <= self.min_stack[-1]:
            self.min_stack.append(val)
        else:
            self.min_stack.append(self.min_stack[-1])

    def pop(self) -> None:
        if self.stack:
            self.stack.pop()
            self.min_stack.pop()

    def top(self) -> int:
        if self.stack:
            return self.stack[-1]
        # Or raise an error if stack is empty, depending on requirements.
        # For typical Min Stack problems, top() is only called on non-empty stacks.
        return None 

    def getMin(self) -> int:
        if self.min_stack:
            return self.min_stack[-1]
        # Or raise an error if stack is empty.
        return None


